/**
 * codex-entries.ts
 *
 * The Er Gen (Ergenverse) codex content module.
 * Single source of in-world lore entries for the Living Cultivation World simulator.
 *
 * Lore is faithful to:
 *   - Renegade Immortal (Wang Lin)
 *   - Pursuit of Truth (Su Ming)
 *   - I Shall Seal the Heavens (Meng Hao)
 *   - A Will Eternal (Bai Xiaochun)
 *   - A World Worth Protecting (Wang Baole)
 *   - Outside of Time (Xu Qing)
 *
 * Tone: scholarly, in-world, evocative xianxia. These entries are written as if
 * compiled by a wandering scholar of the Azure Cloud Continent for the edification
 * of cultivators who would otherwise know only their own village's hearsay.
 *
 * See `/home/z/my-project/docs/ergen-knowledge-base.md` for the canonical lore.
 */

export type CodexCategory =
  | 'cosmology' | 'realms' | 'dao' | 'beasts' | 'alchemy'
  | 'artifacts' | 'formations' | 'talismans' | 'factions'
  | 'geography' | 'history' | 'terminology' | 'legends';

export type CodexLayer = 'world' | 'simulation' | 'personal';

// Structured data for beast entries
export interface BeastData {
  classification: string;       // Ancient Beast, Spirit Beast, Demon Cultivator, etc.
  realm: string;                // Third Step, Nascent Soul, etc.
  temperament: string;          // Dormant, Aggressive, Cunning, etc.
  diet: string;                 // Void Qi, Spiritivore, Carnivore, etc.
  habitat: string;              // Deep Cosmos, Forest, Ocean, etc.
  threat: string;               // Catastrophic, High, Moderate, etc.
  bodyMaterials?: string[];     // Eyes, Blood, Bones, Scale, Organs
  weaknesses?: string[];
  knownEnemies?: string[];
  cultivationValue?: string;
  alchemyUses?: string[];
  artifactUses?: string[];
  bodyRefinementUses?: string[];
  relatedDao?: string[];
  knownInheritances?: string[];
}

// Structured data for herb entries
export interface HerbData {
  element: string;
  temperature: string;          // Cold, Hot, Neutral
  affinity: string[];           // Life, Yin, Wood, etc.
  growthCycle: string;          // Thirty years, Seasonal, etc.
  bestHabitat: string;          // Spirit Veins, Wetlands, etc.
  harvestDifficulty: string;    // Medium, Hard, Extreme
  knownRecipes?: number;
  alchemyProperties?: string[];
  knownMutations?: number;
}

// Structured data for sect/faction entries
export interface SectData {
  founded: string;
  founder?: string;
  currentPatriarch?: string;
  population?: number;
  averageRealm?: string;
  spiritVeins?: number;
  outerDisciples?: number;
  innerDisciples?: number;
  coreDisciples?: number;
  grandElders?: number;
  enemies?: string[];
  allies?: string[];
  knownTechniques?: string[];
  politics?: string;
  currentCrisis?: string;
}

// Structured data for technique entries
export interface TechniqueData {
  grade: string;
  element: string;
  realmRequirement: string;
  qiCost: string;
  learningDifficulty: string;
  creator?: string;
  knownUsers?: string[];
  counteredBy?: string[];
  compatibleConstitutions?: string[];
  evolutionPaths?: string[];
  variants?: string[];
}

export interface CodexEntry {
  id: string;
  category: CodexCategory;
  layer: CodexLayer;             // 'world' = player-facing lore, 'simulation' = dev mechanics, 'personal' = save-specific
  title: string;
  subtitle?: string;
  body: string;                  // In-world prose ONLY for 'world' layer. No formulas, no "In the simulation..."
  tags?: string[];
  relatedEntries?: string[];     // IDs of connected entries (hyperlink graph)
  // Discovery state (for living codex — entries start incomplete and expand)
  discoveryState?: 'unknown' | 'rumored' | 'partially_known' | 'fully_known' | 'researched';
  discoveryRequirements?: string[]; // What the player must do to unlock more info
  // Structured data (optional, per category)
  beastData?: BeastData;
  herbData?: HerbData;
  sectData?: SectData;
  techniqueData?: TechniqueData;
  // Player-specific (for personal codex entries generated during play)
  playerNotes?: string[];        // Observations the player has made
  npcCommentary?: string[];      // What NPC scholars say about this
  lastUpdated?: number;          // Game year when entry was last updated
}

